import { describe, expect, it } from 'vitest';

import {
  adist,
  admitSameDevice,
  deviceA,
  deviceA2,
  deviceB,
  fpDistance,
  MicrophoneFingerprintMaster,
  mismatchPenalty,
  nonTrivial,
  totalGain,
  trivialFp,
  type Fingerprint,
} from '../src/microphone-fingerprint';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(12, 9)).toBe(3);
    expect(adist(9, 12)).toBe(3);
    expect(adist(0, 14)).toBe(14);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('fpDistance (mirrors fpDistance / fpDistance_self)', () => {
  it('is zero from a fingerprint to itself (provenance is reflexive)', () => {
    expect(fpDistance(deviceA, deviceA)).toBe(0);
    expect(fpDistance(deviceB, deviceB)).toBe(0);
    expect(fpDistance(trivialFp, trivialFp)).toBe(0);
  });

  it('is the summed pointwise adist of aligned bands', () => {
    // 0 + 1 + 1 + 0 = 2
    expect(fpDistance(deviceA, deviceA2)).toBe(2);
    // 9 + 7 + 9 + 6 = 31
    expect(fpDistance(deviceA, deviceB)).toBe(31);
  });

  it('returns the large mismatch sentinel on a length mismatch', () => {
    expect(fpDistance([1, 2, 3], [1, 2])).toBe(mismatchPenalty);
    expect(fpDistance([], [0])).toBe(mismatchPenalty);
    expect(mismatchPenalty).toBeGreaterThan(31);
  });
});

describe('non-triviality gate (mirrors totalGain / nonTrivialB)', () => {
  it('sums the per-band gains', () => {
    expect(totalGain(deviceA)).toBe(28);
    expect(totalGain(trivialFp)).toBe(0);
  });

  it('a fingerprint carrying gain is non-trivial', () => {
    expect(nonTrivial(deviceA)).toBe(true);
    expect(nonTrivial(deviceB)).toBe(true);
  });

  it('an all-zero fingerprint is trivial (no device identity)', () => {
    expect(nonTrivial(trivialFp)).toBe(false);
    const allZero: Fingerprint = [0, 0];
    expect(nonTrivial(allZero)).toBe(false);
  });
});

describe('promotion check: admitSameDevice', () => {
  it('admits when non-trivial fingerprints match within tolerance', () => {
    // mirrors same_device_admitted
    const a = admitSameDevice(deviceA, deviceA2, { tol: 3 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.matched).toBe(true);
    expect(a.nonTrivial).toBe(true);
    expect(a.distance).toBe(2);
    expect(a.limitation).toBe('none');
  });

  it('withholds when the fingerprints are a different device (separation > tol)', () => {
    // mirrors different_device_refuted
    const a = admitSameDevice(deviceA, deviceB, { tol: 3 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('different_device');
    expect(a.matched).toBe(false);
    expect(a.distance).toBe(31);
  });

  it('does not admit a trivial self-match (no device identity)', () => {
    // mirrors trivial_fingerprint_rejected: distance 0 but fails non-triviality
    const a = admitSameDevice(trivialFp, trivialFp, { tol: 3 });
    expect(a.outcome).not.toBe('claim_admitted');
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('no_device_identity');
    expect(a.distance).toBe(0);
    expect(a.nonTrivial).toBe(false);
  });

  it('withholds a trivial fingerprint that is also separated', () => {
    const a = admitSameDevice(trivialFp, deviceA, { tol: 3 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_device_identity');
  });

  it('treats a length mismatch as a non-match (sentinel distance)', () => {
    const a = admitSameDevice(deviceA, [12, 8, 5], { tol: 3 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('different_device');
    expect(a.distance).toBe(mismatchPenalty);
  });
});

describe('MicrophoneFingerprintMaster (mirrors mic_fingerprint_master)', () => {
  it('every boundary witness holds', () => {
    expect(MicrophoneFingerprintMaster.fpDistanceSelfZero).toBe(true);
    expect(MicrophoneFingerprintMaster.deviceARecordingsMatch).toBe(true);
    expect(MicrophoneFingerprintMaster.deviceBNotMatch).toBe(true);
    expect(MicrophoneFingerprintMaster.deviceANonTrivial).toBe(true);
    expect(MicrophoneFingerprintMaster.trivialFpRejected).toBe(true);
    expect(MicrophoneFingerprintMaster.devicesWellSeparated).toBe(true);
    expect(MicrophoneFingerprintMaster.trivialFingerprintRejected).toBe(true);
  });
});
